+  def url(*) nil end
+  def name(*) nil end
+  def desc(*) nil end
+  def homepage(*) nil end
+  def livecheck(*) nil end
+  def conflicts_with(*) nil end
+  def depends_on(*) nil end
+  def caveats(*) nil end
+  def app(*) nil end
+  def binary(*) nil end
+  def pkg(*) nil end
+  def font(*) nil end
+  def uninstall(*) nil end
+  def zap(*) nil end
